/*
 * PCI probe - called when device is detected
 */
static int device_probe(struct pci_dev *pdev, const struct pci_device_id *id)
{
    struct net_device *netdev;
    struct net_device_priv *priv;
    int err;
    
    pr_info("%s: Probing device %04x:%04x\n", DRIVER_NAME, 
            pdev->vendor, pdev->device);
    
    /* Enable PCI device */
    err = pci_enable_device(pdev);
    if (err) {
        dev_err(&pdev->dev, "Cannot enable PCI device\n");
        return err;
    }
    
    /* Request PCI regions */
    err = pci_request_regions(pdev, DRIVER_NAME);
    if (err) {
        dev_err(&pdev->dev, "Cannot request PCI regions\n");
        goto err_disable_device;
    }
    
    /* Set DMA mask */
    err = dma_set_mask_and_coherent(&pdev->dev, DMA_BIT_MASK(64));
    if (err) {
        err = dma_set_mask_and_coherent(&pdev->dev, DMA_BIT_MASK(32));
        if (err) {
            dev_err(&pdev->dev, "No usable DMA configuration\n");
            goto err_release_regions;
        }
    }
    
    pci_set_master(pdev);
    
    /* Allocate network device */
    netdev = alloc_etherdev(sizeof(struct net_device_priv));
    if (!netdev) {
        err = -ENOMEM;
        goto err_release_regions;
    }
    
    SET_NETDEV_DEV(netdev, &pdev->dev);
    pci_set_drvdata(pdev, netdev);
    
    priv = netdev_priv(netdev);
    priv->pdev = pdev;
    priv->netdev = netdev;
    
    /* Map MMIO region - TODO: Adjust BAR index */
    priv->mmio_base = pci_iomap(pdev, 0, 0);
    if (!priv->mmio_base) {
        dev_err(&pdev->dev, "Cannot map MMIO region\n");
        err = -ENOMEM;
        goto err_free_netdev;
    }
    
    /* Initialize locks */
    spin_lock_init(&priv->lock);
    mutex_init(&priv->mutex);
    
    /* TODO: Reset hardware */
    /* TODO: Read MAC address from EEPROM/hardware */
    /* For now, use random MAC */
    eth_hw_addr_random(netdev);
    
    /* Setup network device */
    netdev->netdev_ops = &net_netdev_ops;
    netdev->irq = pdev->irq;
    
    /* Register interrupt handler */
    err = request_irq(pdev->irq, device_irq_handler, IRQF_SHARED,
                      DRIVER_NAME, netdev);
    if (err) {
        dev_err(&pdev->dev, "Cannot request IRQ\n");
        goto err_iounmap;
    }
    
    /* Register network device */
    err = register_netdev(netdev);
    if (err) {
        dev_err(&pdev->dev, "Cannot register network device\n");
        goto err_free_irq;
    }
    
    pr_info("%s: Device registered: %s\n", DRIVER_NAME, netdev->name);
    
    return 0;

err_free_irq:
    free_irq(pdev->irq, netdev);
err_iounmap:
    pci_iounmap(pdev, priv->mmio_base);
err_free_netdev:
    free_netdev(netdev);
err_release_regions:
    pci_release_regions(pdev);
err_disable_device:
    pci_disable_device(pdev);
    
    return err;
}

/*
 * PCI remove - called when device is removed
 */
static void device_remove(struct pci_dev *pdev)
{
    struct net_device *netdev = pci_get_drvdata(pdev);
    struct net_device_priv *priv = netdev_priv(netdev);
    
    pr_info("%s: Removing device\n", DRIVER_NAME);
    
    /* Unregister network device */
    unregister_netdev(netdev);
    
    /* Free IRQ */
    free_irq(pdev->irq, netdev);
    
    /* Unmap MMIO */
    pci_iounmap(pdev, priv->mmio_base);
    
    /* Free network device */
    free_netdev(netdev);
    
    /* Release PCI resources */
    pci_release_regions(pdev);
    pci_disable_device(pdev);
}

